class IndexedMinHeap:
    def __init__(self):
        self.heap = []    # (priority, key)
        self.pos  = {}    # key -> index in heap

    def push(self, key, priority):
        self.heap.append((priority, key))
        self.pos[key] = len(self.heap) - 1
        self._sift_up(len(self.heap) - 1)

    def pop(self):
        self._swap(0, len(self.heap) - 1)
        pri, key = self.heap.pop()
        del self.pos[key]
        if self.heap: self._sift_down(0)
        return key, pri

    def decrease_key(self, key, new_priority):
        i = self.pos[key]
        self.heap[i] = (new_priority, key)
        ___________             # sift up since priority decreased

    def _swap(self, i, j):
        self.heap[i], self.heap[j] = self.heap[j], self.heap[i]
        self.pos[self.heap[i][1]] = i
        self.pos[self.heap[j][1]] = j

    def _sift_up(self, i):
        while i > 0:
            p = (i - 1) // 2
            if self.heap[p][0] > self.heap[i][0]:
                self._swap(p, i); i = p
            else: break

    def _sift_down(self, i):
        n = len(self.heap)
        while True:
            s = i; l, r = 2*i+1, 2*i+2
            if l < n and self.heap[l][0] < self.heap[s][0]: s = l
            if r < n and self.heap[r][0] < self.heap[s][0]: s = r
            if s == i: break
            self._swap(i, s); i = s
